import { FunctionComponent } from "react";
import {StyledCard} from "./index.style";
import {Cat} from "app-types/cat";

interface CardProps {
    cat: Cat;

}

type Props = CardProps & React.HtmlHTMLAttributes<HTMLDivElement>;

const Card: FunctionComponent<Props> = ({cat, ...rest}) => {
    return <StyledCard $catId={cat.id} {...rest}></StyledCard>
}

export default Card;
